    <div></div>

    <!-- ===== MAIN CARD ===== -->
    <div class="w-full max-w-md mx-auto relative z-10 bg-white border border-slate-200 p-8 md:p-10 rounded-none card-enter"
         style="box-shadow: 6px 6px 0px 0px rgba(9,76,178,0.12);">

      <!-- Header with small wellness icon -->
      <div class="mb-8">
        <div class="flex items-center gap-2 mb-3">
          <div class="w-8 h-8 flex items-center justify-center rounded-none" style="background:rgba(9,76,178,0.08); border:1px solid rgba(51,102,204,0.2);">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#3366cc" stroke-width="2.5" stroke-linecap="round"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>
          </div>
          <span class="text-[9px] font-black uppercase tracking-widest text-slate-400">Centro de Bienestar Integral</span>
        </div>
        <h2 class="text-2xl font-black text-slate-900 tracking-tight uppercase">
          ACCEDER AL PORTAL
        </h2>
        <p class="text-slate-500 text-xs mt-1.5 leading-relaxed">
          Ingresa tus credenciales para acceder a tus programas de formación.
        </p>
        <!-- Decorative line with gradient -->
        <div class="mt-4 h-0.5 w-16 rounded-full" style="background: linear-gradient(90deg, #094cb2, #3366cc, transparent);"></div>
      </div>

      <!-- Form -->
      <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="space-y-5">

        <!-- Error alert -->
        @if (errorMessage) {
          <div class="flex items-start gap-3 bg-red-50 border border-red-200 text-red-800 p-4 rounded-none text-xs font-semibold">
            <span class="material-symbols-outlined text-red-600 text-base mt-0.5">warning</span>
            <div class="flex-grow">
              <span class="block font-bold">Error al ingresar</span>
              <span class="block font-normal mt-0.5 text-red-600">{{ errorMessage }}</span>
            </div>
          </div>
        }

        <!-- Email field -->
        <div>
          <label class="block text-[10px] font-bold text-slate-600 mb-1.5 uppercase tracking-widest" for="email">
            Correo Electrónico
          </label>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none" style="color:#3366cc; opacity:0.6;">
              <span class="material-symbols-outlined text-lg">mail</span>
            </div>
            <input
              formControlName="correo"
              class="input-wellness block w-full pl-10 pr-3 py-3 border border-slate-200 rounded-none bg-slate-50 text-slate-900 text-sm placeholder-slate-400"
              id="email"
              placeholder="correo@institución.com"
              type="email">
          </div>
          @if (loginForm.get('correo')?.hasError('required') && loginForm.get('correo')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px]">info</span>
              El correo es obligatorio.
            </p>
          }
          @if (loginForm.get('correo')?.hasError('email') && loginForm.get('correo')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px]">info</span>
              El formato de correo no es válido.
            </p>
          }
        </div>

        <!-- Password field -->
        <div>
          <div class="flex items-center justify-between mb-1.5">
            <label class="block text-[10px] font-bold text-slate-600 uppercase tracking-widest" for="password">
              Contraseña
            </label>
            <a (click)="openRecoveryModal(); $event.preventDefault()"
               class="text-[10px] font-bold uppercase tracking-wider cursor-pointer transition-colors hover:underline"
               style="color:#3366cc;">
              ¿La olvidaste?
            </a>
          </div>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none" style="color:#3366cc; opacity:0.6;">
              <span class="material-symbols-outlined text-lg">lock</span>
            </div>
            <input
              formControlName="password"
              [type]="hidePassword ? 'password' : 'text'"
              class="input-wellness block w-full pl-10 pr-10 py-3 border border-slate-200 rounded-none bg-slate-50 text-slate-900 text-sm"
              id="password"
              placeholder="••••••••">
            <button
              type="button"
              (click)="hidePassword = !hidePassword"
              class="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 transition-colors">
              <span class="material-symbols-outlined text-base">
                {{ hidePassword ? 'visibility' : 'visibility_off' }}
              </span>
            </button>
          </div>
          @if (loginForm.get('password')?.hasError('required') && loginForm.get('password')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px]">info</span>
              La contraseña es obligatoria.
            </p>
          }
        </div>

        <!-- Remember me -->
        <div class="flex items-center">
          <input
            formControlName="rememberMe"
            class="h-4 w-4 border-slate-300 rounded-none bg-white"
            id="remember-me"
            type="checkbox"
            style="accent-color: #094cb2;">
          <label class="ml-2 block text-xs text-slate-600 font-medium select-none" for="remember-me">
            Mantener sesión iniciada
          </label>
        </div>

        <!-- Submit button with glow -->
        <button
          [disabled]="loginForm.invalid || isLoading"
          class="btn-glow w-full flex justify-center items-center gap-2 py-3.5 px-4 border-0 rounded-none text-xs font-bold text-white uppercase tracking-widest transition-all disabled:opacity-40 disabled:cursor-not-allowed"
          style="background: linear-gradient(135deg, #094cb2 0%, #3366cc 100%);"
          onmouseover="this.style.background='linear-gradient(135deg, #00419d 0%, #2259bf 100%)'"
          onmouseout="this.style.background='linear-gradient(135deg, #094cb2 0%, #3366cc 100%)'"
          type="submit">
          @if (isLoading) {
            <span class="animate-spin inline-block w-4 h-4 border-2 border-white border-t-transparent rounded-full"></span>
            Verificando acceso...
          } @else {
            <span>Ingresar al Portal</span>
            <span class="material-symbols-outlined text-sm font-bold">arrow_forward</span>
          }
        </button>
      </form>

      <!-- Demo quick access -->
      <div class="mt-7 pt-6 border-t border-slate-100">
        <span class="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 text-center">Acceso Rápido de Prueba</span>
        <div class="grid grid-cols-2 gap-3">
          <button
            type="button"
            (click)="autofill('admin')"
            class="flex flex-col items-center justify-center p-3 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 transition-all rounded-none text-center group">
            <span class="material-symbols-outlined text-lg mb-1 transition-colors" style="color:#3366cc;">admin_panel_settings</span>
            <span class="text-xs font-bold text-slate-800">Administrador</span>
            <span class="text-[9px] text-slate-500 mt-0.5">admin&#64;insteip.com</span>
          </button>
          <button
            type="button"
            (click)="autofill('student')"
            class="flex flex-col items-center justify-center p-3 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 transition-all rounded-none text-center">
            <span class="material-symbols-outlined text-lg mb-1" style="color:#bfab49;">school</span>
            <span class="text-xs font-bold text-slate-800">Terapeuta / Alumno</span>
            <span class="text-[9px] text-slate-500 mt-0.5">juan.perez&#64;insteip.com</span>
          </button>
        </div>
      </div>
    </div>

    <!-- Footer right -->
    <div class="w-full max-w-md mx-auto mt-6 text-center text-[10px] text-slate-400 relative z-10">
      <div class="flex justify-center gap-4 mb-2">
        <a class="hover:text-slate-600 transition-colors" href="#">Términos de servicio</a>
        <span>•</span>
        <a class="hover:text-slate-600 transition-colors" href="#">Privacidad</a>
        <span>•</span>
        <a class="hover:text-slate-600 transition-colors" href="#">Soporte</a>
      </div>
      <p>© 2026 INSTEIP · Terapias Alternativas y Complementarias</p>
    </div>
  </div>

  <!-- =============================================
       PASSWORD RECOVERY MODAL (unchanged logic, refreshed style)
       ============================================= -->
  <div *ngIf="showRecoveryModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden relative card-enter">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-100 flex items-center justify-between"
           style="background: rgba(9,76,178,0.04);">
        <div class="flex items-center gap-2">
          <span class="material-symbols-outlined text-base" style="color:#3366cc;">lock_reset</span>
          <h3 class="text-xs font-black text-slate-900 uppercase tracking-widest">Recuperación de Contraseña</h3>
        </div>
        <button (click)="closeRecoveryModal()" class="text-slate-400 hover:text-slate-600 transition-colors">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <div class="p-6 space-y-4">
        <!-- Error message -->
        <div *ngIf="recoveryError" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ recoveryError }}</span>
        </div>

        <!-- Success message -->
        <div *ngIf="recoveryMessage" class="flex items-start gap-2 bg-emerald-50 border border-emerald-200 text-emerald-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-emerald-600 text-base">check_circle</span>
          <span>{{ recoveryMessage }}</span>
        </div>

        <!-- STEP 1: Request code -->
        <div *ngIf="recoveryStep === 1" class="space-y-4">
          <p class="text-xs text-slate-500 leading-relaxed">
            Ingresa tu correo electrónico registrado. Si coincide con tu cuenta, te enviaremos un código de recuperación temporal de 6 dígitos.
          </p>
          <div>
            <label class="block text-[10px] font-bold text-slate-600 mb-1.5 uppercase tracking-widest">Correo Electrónico</label>
            <input
              [(ngModel)]="recoveryEmail"
              type="email"
              class="input-wellness w-full px-3 py-2 border border-slate-200 bg-slate-50 text-slate-900 text-xs rounded-none"
              placeholder="correo@institución.com">
          </div>
          <button
            (click)="onRequestToken()"
            [disabled]="isRecoveryLoading"
            class="w-full py-2.5 text-white font-bold text-xs uppercase tracking-widest transition-colors rounded-none disabled:opacity-50"
            style="background: linear-gradient(135deg, #094cb2 0%, #3366cc 100%);">
            {{ isRecoveryLoading ? 'Solicitando...' : 'Enviar Código de Acceso' }}
          </button>
        </div>

        <!-- STEP 2: Enter code and new password -->
        <div *ngIf="recoveryStep === 2" class="space-y-4">
          <p class="text-xs text-slate-500 leading-relaxed">
            Introduce el código temporal recibido por correo y escribe tu nueva contraseña.
          </p>
          <div>
            <label class="block text-[10px] font-bold text-slate-600 mb-1.5 uppercase tracking-widest">Código de Recuperación</label>
            <input
              [(ngModel)]="recoveryToken"
              type="text"
              class="input-wellness w-full px-3 py-2 border border-slate-200 bg-slate-50 text-slate-900 text-xs rounded-none font-mono text-center tracking-widest"
              placeholder="Ej. 123456">
          </div>
          <div>
            <label class="block text-[10px] font-bold text-slate-600 mb-1.5 uppercase tracking-widest">Nueva Contraseña</label>
            <input
              [(ngModel)]="recoveryNewPassword"
              type="password"
              class="input-wellness w-full px-3 py-2 border border-slate-200 bg-slate-50 text-slate-900 text-xs rounded-none"
              placeholder="Mínimo 6 caracteres">
          </div>
          <button
            (click)="onResetPassword()"
            [disabled]="isRecoveryLoading"
            class="w-full py-2.5 text-white font-bold text-xs uppercase tracking-widest transition-colors rounded-none disabled:opacity-50"
            style="background: linear-gradient(135deg, #094cb2 0%, #3366cc 100%);">
            {{ isRecoveryLoading ? 'Restableciendo...' : 'Restablecer Contraseña' }}
          </button>
        </div>
      </div>
    </div>
  </div>

</main>
